import React from "react";
import AllCompo from "../components/AllCompo";
import Footer from "../components/Footer";
import { CartProvider } from "react-use-cart";
import { useContext } from "react";
import { apiValue } from "../Data/AllData";

function Page() {
  const data = useContext(apiValue);
  return (
    <div>
      <AllCompo />
      <div className="section properties">
        <div className="container">
          <div className="row properties-box">
            {data.map((item) => {
              return (
                <div className="col-lg-4 col-md-6 align-self-center mb-30 properties-items col-md-6 adv">
                  <div className="item">
                    <a href="property-details.html">
                      <img src={item.images[0]} alt="" />
                    </a>
                    <span className="category">{item.brand}</span>
                    <h6>$2.264.000</h6>
                    <h4>
                      <a href="property-details.html">
                        {item.title}
                      </a>
                    </h4>
                    <ul>
                      <li>
                        category: <span>{item.category}</span>
                      </li>
                      <li>
                        ID: <span>{item.id}</span>
                      </li>
                      <li>
                        Area: <span>545m2</span>
                      </li>
                      <li>
                        Floor: <span>3</span>
                      </li>
                      <li>
                        Parking: <span>6 spots</span>
                      </li>
                    </ul>
                    <div className="main-button">
                      <a href="property-details.html">Schedule a visit</a>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
      <Footer />
    </div>
  );
}

function AllProduct() {
  return (
    <CartProvider>
      <Page />
    </CartProvider>
  );
}

export default AllProduct;
